create extension if not exists pgcrypto;
do $$ begin create type public.order_type as enum ('delivery', 'pickup'); exception when duplicate_object then null; end $$;
do $$ begin create type public.order_status as enum ('pending', 'approved', 'completed', 'canceled'); exception when duplicate_object then null; end $$;
create table if not exists public.site_settings ( id uuid primary key default gen_random_uuid(), business_name text not null default 'החווה', slogan text not null default 'מהמשק לצלחת', phone text not null default '050-0000000', whatsapp_url text not null default 'https://wa.me/972500000000', email text not null default 'hachava2026@gmail.com', instagram_url text not null default 'https://www.instagram.com/hachava_meat', address text not null default 'קניון גנים', opening_hours jsonb not null default jsonb_build_object('sun_thu','09:00–21:00','fri','09:00–14:00'), hero_title text not null default 'בשר איכותי מהמשק', hero_subtitle text not null default 'כשרות, טריות, איכות ושירות אישי ברמה גבוהה', about_title text not null default 'על החווה', about_body text not null default 'בהחווה אנחנו מאמינים שבשר איכותי מתחיל במקצוענות, טריות וכבוד לחומר הגלם. אנו מגישים חוויית קנייה חמה, משפחתית ויוקרתית, עם הקפדה על איכות בלתי מתפשרת — מהמשק לצלחת.', kosher_label text not null default 'כשר', map_embed_url text, logo_url text, updated_at timestamptz not null default now() );
create table if not exists public.product_categories ( id uuid primary key default gen_random_uuid(), slug text unique not null, name_he text not null, sort_order integer not null default 0, image_url text, is_active boolean not null default true, created_at timestamptz not null default now() );
create table if not exists public.products ( id uuid primary key default gen_random_uuid(), category_id uuid not null references public.product_categories(id) on delete cascade, name_he text not null, description_he text, image_url text, is_active boolean not null default true, sort_order integer not null default 0, created_at timestamptz not null default now() );
create table if not exists public.promotions ( id uuid primary key default gen_random_uuid(), title_he text not null, description_he text not null, image_url text, is_active boolean not null default false, starts_at timestamptz, ends_at timestamptz, created_at timestamptz not null default now(), updated_at timestamptz not null default now() );
create table if not exists public.orders ( id uuid primary key default gen_random_uuid(), customer_name text not null, phone text not null, address text, notes text, order_type public.order_type not null, status public.order_status not null default 'pending', created_at timestamptz not null default now() );
create table if not exists public.order_items ( id uuid primary key default gen_random_uuid(), order_id uuid not null references public.orders(id) on delete cascade, product_id uuid not null references public.products(id) on delete restrict, product_name_snapshot text not null, quantity integer not null check (quantity > 0) );
create table if not exists public.content_blocks ( id uuid primary key default gen_random_uuid(), key text unique not null, title_he text, body_he text, image_url text, updated_at timestamptz not null default now() );
create table if not exists public.admin_users ( user_id uuid primary key, email text unique not null, role text not null default 'admin', created_at timestamptz not null default now() );
create or replace function public.create_order_with_items(p_customer_name text,p_phone text,p_address text,p_notes text,p_order_type public.order_type,p_items jsonb) returns uuid language plpgsql security definer as $$ declare v_order_id uuid; v_item jsonb; begin insert into public.orders (customer_name, phone, address, notes, order_type) values (p_customer_name, p_phone, p_address, p_notes, p_order_type) returning id into v_order_id; for v_item in select * from jsonb_array_elements(p_items) loop insert into public.order_items (order_id, product_id, product_name_snapshot, quantity) select v_order_id, (v_item->>'product_id')::uuid, p.name_he, (v_item->>'quantity')::integer from public.products p where p.id = (v_item->>'product_id')::uuid; end loop; return v_order_id; end; $$;
alter table public.site_settings enable row level security; alter table public.product_categories enable row level security; alter table public.products enable row level security; alter table public.promotions enable row level security; alter table public.orders enable row level security; alter table public.order_items enable row level security; alter table public.content_blocks enable row level security; alter table public.admin_users enable row level security;
